var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오늘은 건틀렛 보는 날.","JPN":"今日はガントレットを見る日。","ENG":"Today is Gauntlet day.","TWN":"今天是觀看聖鎧比賽的日子。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"엄마랑 아빠는 더 큰 다음에 보라고 했지만 괜찮아.","JPN":"ママとパパはもっと大きくなってから見てねって言ったけど、大丈夫。","ENG":"Mom and Dad told me to watch when I'm older, but it's okay.","TWN":"爸爸媽媽叫我長大後再看，但是沒關係。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"엄마랑 아빠는 일 때문에 늦게 온다고 하셨으니까.","JPN":"ママとパパは仕事で遅くなるって言ったから。","ENG":"They said that they're going to be late tonight.","TWN":"他們說因為工作的關係會晚點回來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까 저건, 엄마가 아니야.","JPN":"だからあれは、ママじゃない。","ENG":"So that woman isn't my mother.","TWN":"所以，那個人不是媽媽。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>새로운 본선 진출 팀을 환영해 주시기 바랍니다! 카나리아 스쿼드!</color>","JPN":"<color=#ffd34c>新しく本選に進出したチームを歓迎してください！　カナリア・スクワッド！</color>","ENG":"<color=#ffd34c>Please welcome the newest team that made it to the elimination rounds! Canary Squad!</color>","TWN":"<color=#ffd34c>讓我們歡迎打入決賽的隊伍！金絲雀小隊！</color>"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"다들 고생했어!","JPN":"みんな、お疲れ様！","ENG":"Good work, everyone!","TWN":"大家都辛苦啦！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아…… 죽겠다. 일단 의무실부터 가야겠어.","JPN":"あ……死ぬ。とりあえず医務室から行こう。","ENG":"Gah... I'm this close from passing out. I need to go to the infirmary first.","TWN":"呃……我快死啦，我要先去醫務室。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도요. 온몸의 힘이 쭉 빠진 기분이에요…….","JPN":"私もです。全身の力が抜けちゃった気分ですよ……","ENG":"Me too. I feel as if all my energy has been drained...","TWN":"我也是，感覺筋疲力盡的……"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치! 들었죠? 본선 진출이래요!","JPN":"コーチ！　聞きました？　本選進出ですって！","ENG":"Coach! Did you hear that? We made it to the elimination rounds!","TWN":"教練！你有聽到嗎？我們打入決賽了！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"수고 많았네. 펠리세트.","JPN":"ご苦労様。フェリセット。","ENG":"Good work, Félicette.","TWN":"辛苦你囉，費莉塞特。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 리그에서 데뷔한 시즌에 본선 진출을 이룬 팀은 서른 개밖에 없어요.","JPN":"シャレードガントレットリーグで、デビューしたシーズンに本選進出に成功したチームは30チームしかありません。","ENG":"There are only thirty teams in Charade Gauntlet League history who made it to the elimination rounds on their debut season.","TWN":"在查雷德聖鎧聯賽的歷史上，只有三十支隊伍首次參賽就打進決賽。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희가 바로 그 서른 번째구요.","JPN":"私たちがその30番目です。","ENG":"We are the thirtieth.","TWN":"我們就是那第三十個。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"정말 대단한 성과예요. 어쩌면 어제 갔던 박물관에 기록될지도 모를 만큼.","JPN":"本当にすごい成果です。もしかしたら、昨日行った博物館に記録されるかもしれないほどに。","ENG":"This is amazing. We might be recorded in the museum that we went to yesterday.","TWN":"這真的很厲害，說不定會被我們昨天去過的博物館給記錄下來。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그 정도인가?","JPN":"それほどなのか？","ENG":"Is it that impressive?","TWN":"有那麼厲害喔？"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼요. 엔트리를 최소 조건만 만족한 상태로 이룬 결과니까 더 대단한 거예요.","JPN":"もちろんです。エントリーの最小条件だけを満たして成し遂げた結果ですから、もっとすごいんです。","ENG":"Of course it is. Especially since we've accomplished this with the minimum entry requirements.","TWN":"當然。而且我們還是在滿足最低人數條件下贏的，所以更厲害。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"암전 기믹 때 어땠는지 코치도 봤으면 좋았을 텐데.","JPN":"暗転ギミックの時にどうだったか、コーチも見れたらよかったのに。","ENG":"You should have seen what happened during the lights-out gimmick.","TWN":"真希望教練也能看到我們夜戰時的表現。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};